<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { ElMessage } from 'element-plus'
import { api, errorMessage } from '@/api/client'
import { useAuthStore } from '@/stores/auth'
import { businessText, resourceText } from '@/utils/status'
const auth = useAuthStore()
const plans = ref<any[]>([])
const scenarios = ref<any[]>([])
const planDialog = ref(false)
const scenarioDialog = ref(false)
const planEdit = ref<number | null>(null)
const scenarioEdit = ref<number | null>(null)
const plan = reactive<any>({ name: '', business_code: 'fut_mm', description: '', default_resource_ids: [], config_version: '1.0', is_enabled: true })
const scenario = reactive<any>({ plan_id: 0, name: '', scenario_type: 'order', config_version: '1.0', parametersText: '{}', actionsText: '[]', rulesText: '{"max_mean_us":100}', required_resource_types: [], expected_artifacts: [], is_enabled: true })
async function load() { ;[plans.value, scenarios.value] = await Promise.all([api.get('/plans').then(r => r.data), api.get('/scenarios').then(r => r.data)]) }
function openPlan(row?: any) { Object.assign(plan, { name: '', business_code: 'fut_mm', description: '', default_resource_ids: [], config_version: '1.0', is_enabled: true }, row || {}); planEdit.value = row?.id || null; planDialog.value = true }
function openScenario(row?: any, planId?: number) { Object.assign(scenario, { plan_id: planId || plans.value[0]?.id || 0, name: '', scenario_type: 'order', config_version: '1.0', parametersText: '{}', actionsText: '[]', rulesText: '{"max_mean_us":100}', required_resource_types: [], expected_artifacts: [], is_enabled: true }); if (row) { Object.assign(scenario, row, { parametersText: JSON.stringify(row.parameters, null, 2), actionsText: JSON.stringify(row.actions, null, 2), rulesText: JSON.stringify(row.statistics_rules, null, 2) }); scenarioEdit.value = row.id } else scenarioEdit.value = null; scenarioDialog.value = true }
async function savePlan() { try { planEdit.value ? await api.put(`/plans/${planEdit.value}`, plan) : await api.post('/plans', plan); planDialog.value = false; ElMessage.success('方案已保存'); load() } catch (e) { ElMessage.error(errorMessage(e)) } }
async function saveScenario() { try { const data: any = { ...scenario, parameters: JSON.parse(scenario.parametersText), actions: JSON.parse(scenario.actionsText), statistics_rules: JSON.parse(scenario.rulesText) }; delete data.parametersText; delete data.actionsText; delete data.rulesText; scenarioEdit.value ? await api.put(`/scenarios/${scenarioEdit.value}`, data) : await api.post('/scenarios', data); scenarioDialog.value = false; ElMessage.success('场景已保存'); load() } catch (e) { ElMessage.error(errorMessage(e)) } }
async function copyPlan(row: any) { await api.post(`/plans/${row.id}/copy`); ElMessage.success('方案及场景已复制'); load() }
async function copyScenario(row: any) { await api.post(`/scenarios/${row.id}/copy`); ElMessage.success('场景已复制'); load() }
onMounted(load)
</script>
<template><div class="page"><div class="page-header"><div><h1 class="page-title">方案与场景</h1><p class="muted">版本化配置测速流程，历史运行保存独立快照</p></div><el-button v-if="auth.canOperate" type="primary" @click="openPlan()">新增方案</el-button></div><el-collapse class="plans"><el-collapse-item v-for="p in plans" :key="p.id" :name="p.id"><template #title><div class="plan-head"><div><strong>{{p.name}}</strong><el-tag size="small" effect="plain">{{businessText[p.business_code]}}</el-tag><span class="muted">v{{p.config_version}}</span></div><div v-if="auth.canOperate" @click.stop><el-button link type="primary" @click="openScenario(undefined,p.id)">新增场景</el-button><el-button link @click="openPlan(p)">编辑</el-button><el-button link @click="copyPlan(p)">复制</el-button></div></div></template><p class="muted">{{p.description||'暂无描述'}}</p><el-table :data="scenarios.filter(s=>s.plan_id===p.id)" size="small"><el-table-column prop="name" label="场景名称"/><el-table-column prop="scenario_type" label="场景类型"/><el-table-column prop="config_version" label="配置版本"/><el-table-column label="所需资源"><template #default="s"><el-tag v-for="t in s.row.required_resource_types" :key="t" size="small" class="tag">{{resourceText[t]||t}}</el-tag></template></el-table-column><el-table-column label="状态"><template #default="s">{{s.row.is_enabled?'启用':'停用'}}</template></el-table-column><el-table-column v-if="auth.canOperate" width="120"><template #default="s"><el-button link @click="openScenario(s.row)">编辑</el-button><el-button link @click="copyScenario(s.row)">复制</el-button></template></el-table-column></el-table></el-collapse-item></el-collapse><el-dialog v-model="planDialog" :title="planEdit?'编辑方案':'新增方案'" width="600px"><el-form label-width="90px"><el-form-item label="名称"><el-input v-model="plan.name"/></el-form-item><el-form-item label="业务"><el-select v-model="plan.business_code"><el-option v-for="(v,k) in businessText" :key="k" :label="v" :value="k"/></el-select></el-form-item><el-form-item label="配置版本"><el-input v-model="plan.config_version"/></el-form-item><el-form-item label="描述"><el-input v-model="plan.description" type="textarea"/></el-form-item><el-form-item label="启用"><el-switch v-model="plan.is_enabled"/></el-form-item></el-form><template #footer><el-button @click="planDialog=false">取消</el-button><el-button type="primary" @click="savePlan">保存</el-button></template></el-dialog><el-dialog v-model="scenarioDialog" :title="scenarioEdit?'编辑场景':'新增场景'" width="760px"><el-form label-width="110px"><el-row :gutter="16"><el-col :span="12"><el-form-item label="所属方案"><el-select v-model="scenario.plan_id" style="width:100%"><el-option v-for="p in plans" :key="p.id" :label="p.name" :value="p.id"/></el-select></el-form-item></el-col><el-col :span="12"><el-form-item label="场景名称"><el-input v-model="scenario.name"/></el-form-item></el-col><el-col :span="12"><el-form-item label="场景类型"><el-input v-model="scenario.scenario_type"/></el-form-item></el-col><el-col :span="12"><el-form-item label="配置版本"><el-input v-model="scenario.config_version"/></el-form-item></el-col><el-col :span="24"><el-form-item label="所需资源"><el-select v-model="scenario.required_resource_types" multiple style="width:100%"><el-option v-for="(v,k) in resourceText" :key="k" :label="v" :value="k"/></el-select></el-form-item></el-col><el-col :span="24"><el-form-item label="参数 JSON"><el-input v-model="scenario.parametersText" type="textarea" :rows="3" class="mono"/></el-form-item></el-col><el-col :span="24"><el-form-item label="动作 JSON"><el-input v-model="scenario.actionsText" type="textarea" :rows="3" class="mono"/></el-form-item></el-col><el-col :span="24"><el-form-item label="统计规则 JSON"><el-input v-model="scenario.rulesText" type="textarea" :rows="3" class="mono"/></el-form-item></el-col></el-row></el-form><template #footer><el-button @click="scenarioDialog=false">取消</el-button><el-button type="primary" @click="saveScenario">保存</el-button></template></el-dialog></div></template>
<style scoped>.plans{border:0}.plans :deep(.el-collapse-item){background:#fff;border:1px solid #e5eaf0;border-radius:12px;margin-bottom:12px;padding:0 18px}.plan-head{width:100%;display:flex;align-items:center;justify-content:space-between;padding-right:16px}.plan-head strong{font-size:16px;margin-right:12px}.plan-head .el-tag{margin-right:10px}.tag{margin-right:5px}</style>
